    :item=\"item\"\n        @toggle=\"$emit('toggle-item', idx)\"\n      />\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport type { WidgetGroup } from './schema';\nimport WidgetItem from './WidgetItem.vue';\n\nconst props = defineProps<{\n  group: WidgetGroup;\n}>();\n\ndefineEmits<{\n  'toggle-group': [];\n  'toggle-item': [itemIdx: number];\n}>();\n\nconst collapsed = ref(false);\n\nconst enabledCount = computed(() => props.group.items.filter(i => i.enabled).length);\nconst allEnabled = computed(() => props.group.items.length > 0 && props.group.items.every(i => i.enabled));\nconst someEnabled = computed(() => props.group.items.some(i => i.enabled));\n</script>\n\n<style scoped>\n.widget-group {\n  border: 1px solid rgba(255, 255, 255, 0.06);\n  border-radius: 8px;\n  overflow: hidden;\n  background: rgba(255, 255, 255, 0.02);\n}\n\n.widget-group + .widget-group {\n  margin-top: 8px;\n}\n\n.widget-group__header {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 8px 12px;\n  cursor: pointer;\n  user-select: none;\n  background: rgba(255, 255, 255, 0.03);\n  transition: background 0.2s;\n}\n\n.widget-group__header:hover {\n  background: rgba(255, 255, 255, 0.06);\n}\n\n.widget-group__title-row {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  min-width: 0;\n  flex: 1;\n}\n\n.widget-group__chevron {\n  font-size: 10px;\n  color: rgba(255, 255, 255, 0.4);\n  transition: transform 0.2s;\n  width: 12px;\n  text-align: center;\n}\n\n.widget-group__chevron--open {\n  transform: rotate(90deg);\n}\n\n.widget-group__title {\n  font-size: 13px;\n  font-weight: 600;\n  color: rgba(255, 255, 255, 0.85);\n}\n\n.widget-group__count {\n  font-size: 11px;\n  color: rgba(255, 255, 255, 0.35);\n  margin-left: 4px;\n}\n\n.widget-group__body {\n  padding: 4px 8px 8px;\n}\n\n.widget-group__desc {\n  font-size: 11px;\n  color: rgba(255, 255, 255, 0.4);\n  padding: 2px 10px 6px;\n  margin: 0;\n}\n\n/* --- Group Toggle --- */\n.widget-group__toggle {\n  position: relative;\n  flex-shrink: 0;\n  cursor: pointer;\n}\n\n.widget-group__toggle input {\n  opacity: 0;\n  width: 0;\n  height: 0;\n  position: absolute;\n}\n\n.widget-group__slider {\n  display: block;\n  width: 36px;\n  height: 20px;\n  background: rgba(255, 255, 255, 0.12);\n  border-radius: 10px;\n  position: relative;\n  transition: background 0.25s;\n}\n\n.widget-group__slider::after {\n  content: '';\n  position: absolute;\n  top: 2px;\n  left: 2px;\n  width: 16px;\n  height: 16px;\n  background: rgba(255, 255, 255, 0.5);\n  border-radius: 50%;\n  transition: transform 0.25s, background 0.25s;\n}\n\n.widget-group__toggle input:checked + .widget-group__slider {\n  background: rgba(76, 175, 80, 0.6);\n}\n\n.widget-group__toggle input:checked + .widget-group__slider::after {\n  transform: translateX(16px);\n  background: #4caf50;\n}\n</style>\n"],"sourceRoot":""}]);
